import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

class IssueControllerTest {

    private IssueController controller;

    @BeforeEach
    void setUp() {
        controller = new IssueController();
    }

    @Test
    void createIssue_returnsNewOpenIssueWithGivenTitleAndPriority() {
        Issue issue = controller.createIssue("Login page crashes", "HIGH");

        assertNotNull(issue.getId());
        assertEquals("Login page crashes", issue.getTitle());
        assertEquals("HIGH", issue.getPriority());
        assertEquals("OPEN", issue.getStatus());
    }

    @Test
    void createIssue_throwsWhenTitleIsBlank() {
        IllegalArgumentException ex = assertThrows(
            IllegalArgumentException.class,
            () -> controller.createIssue("", "LOW")
        );
        assertEquals("Title is required", ex.getMessage());
    }
}
